import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { DollarSign, ShoppingCart, TrendingUp, Award } from 'lucide-react';

function PartnerDashboard() {
  const [stats, setStats] = useState({
    totalSales: 0,
    totalRevenue: 0,
    totalCommission: 0,
    paidCommission: 0
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      console.log('Loading partner dashboard...');
      const response = await partnerService.getDashboard();
      console.log('Dashboard response:', response.data);

      if (response.data && response.data.stats) {
        setStats(response.data.stats);
      }
      setError('');
    } catch (err) {
      console.error('Dashboard error:', err);
      setError('Failed to load dashboard. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    if (!amount && amount !== 0) return '₹0.00';
    return `₹${amount.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        minHeight: '400px',
        fontSize: '1.2rem',
        color: '#666'
      }}>
        Loading dashboard...
      </div>
    );
  }

  if (error) {
    return (
      <div style={{
        background: '#ffebee',
        border: '1px solid #ffcdd2',
        color: '#c62828',
        padding: '1rem',
        borderRadius: '8px',
        margin: '2rem'
      }}>
        {error}
        <button 
          onClick={loadData}
          style={{
            marginLeft: '1rem',
            padding: '0.5rem 1rem',
            background: '#c62828',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
          }}
        >
          Retry
        </button>
      </div>
    );
  }

  return (
    <div style={{ padding: '2rem', background: '#f8f9fa', minHeight: '100vh' }}>
      <div style={{ marginBottom: '2rem' }}>
        <h1 style={{ fontSize: '2rem', color: '#333', marginBottom: '0.5rem' }}>Partner Dashboard</h1>
        <p style={{ color: '#666' }}>Track your sales performance</p>
      </div>

      {/* Stats Grid */}
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', 
        gap: '1.5rem',
        marginBottom: '2rem'
      }}>
        <div style={{ 
          background: 'white', 
          padding: '1.5rem', 
          borderRadius: '10px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          display: 'flex',
          alignItems: 'center',
          gap: '1rem'
        }}>
          <div style={{ 
            width: '60px', 
            height: '60px', 
            background: '#fff3e0', 
            borderRadius: '12px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            <ShoppingCart size={24} color="#ff9800" />
          </div>
          <div>
            <h3 style={{ fontSize: '0.875rem', color: '#666', marginBottom: '0.5rem', fontWeight: '500' }}>
              Total Sales
            </h3>
            <p style={{ fontSize: '1.875rem', fontWeight: '700', color: '#333', margin: 0 }}>
              {stats.totalSales || 0}
            </p>
          </div>
        </div>

        <div style={{ 
          background: 'white', 
          padding: '1.5rem', 
          borderRadius: '10px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          display: 'flex',
          alignItems: 'center',
          gap: '1rem'
        }}>
          <div style={{ 
            width: '60px', 
            height: '60px', 
            background: '#e3f2fd', 
            borderRadius: '12px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            <DollarSign size={24} color="#2196f3" />
          </div>
          <div>
            <h3 style={{ fontSize: '0.875rem', color: '#666', marginBottom: '0.5rem', fontWeight: '500' }}>
              Total Revenue
            </h3>
            <p style={{ fontSize: '1.875rem', fontWeight: '700', color: '#2196f3', margin: 0 }}>
              {formatCurrency(stats.totalRevenue || 0)}
            </p>
          </div>
        </div>

        <div style={{ 
          background: 'white', 
          padding: '1.5rem', 
          borderRadius: '10px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          display: 'flex',
          alignItems: 'center',
          gap: '1rem'
        }}>
          <div style={{ 
            width: '60px', 
            height: '60px', 
            background: '#e8f5e9', 
            borderRadius: '12px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            <TrendingUp size={24} color="#4caf50" />
          </div>
          <div>
            <h3 style={{ fontSize: '0.875rem', color: '#666', marginBottom: '0.5rem', fontWeight: '500' }}>
              Total Commission
            </h3>
            <p style={{ fontSize: '1.875rem', fontWeight: '700', color: '#4caf50', margin: 0 }}>
              {formatCurrency(stats.totalCommission || 0)}
            </p>
          </div>
        </div>

        <div style={{ 
          background: 'white', 
          padding: '1.5rem', 
          borderRadius: '10px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          display: 'flex',
          alignItems: 'center',
          gap: '1rem'
        }}>
          <div style={{ 
            width: '60px', 
            height: '60px', 
            background: '#fce4ec', 
            borderRadius: '12px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            <Award size={24} color="#e91e63" />
          </div>
          <div>
            <h3 style={{ fontSize: '0.875rem', color: '#666', marginBottom: '0.5rem', fontWeight: '500' }}>
              Paid Commission
            </h3>
            <p style={{ fontSize: '1.875rem', fontWeight: '700', color: '#e91e63', margin: 0 }}>
              {formatCurrency(stats.paidCommission || 0)}
            </p>
          </div>
        </div>
      </div>

      {/* Empty State */}
      {stats.totalSales === 0 && (
        <div style={{ 
          background: 'white', 
          padding: '3rem', 
          borderRadius: '10px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          textAlign: 'center'
        }}>
          <ShoppingCart size={64} color="#ccc" style={{ marginBottom: '1rem' }} />
          <h3 style={{ fontSize: '1.5rem', color: '#666', marginBottom: '0.5rem' }}>No Sales Yet</h3>
          <p style={{ color: '#999', margin: 0 }}>Start selling products to see your performance metrics!</p>
        </div>
      )}
    </div>
  );
}

export default PartnerDashboard;
